/* --- Main  --- */

int main(void)
{
	if (access(FIXTURE_DIR "/metadata.json", F_OK) != 0) {
		sam3_log_error("tracker fixtures missing at %s",
			       FIXTURE_DIR);
		sam3_log_error("run: python3 scripts/gen_tracker_fixtures.py");
		return 1;
	}

	test_tracker_memory_attn_fixture();
	test_tracker_mask_decoder_fixture();
	test_tracker_memory_encoder_fixture();
	test_tracker_integration_fixture();
	test_tracker_propagation_fixture();

	TEST_REPORT();
}
